import os

def read_user_file(base_dir, filename):
    # 防止路徑穿越：正規化後確認仍在 base_dir 之內
    full = os.path.normpath(os.path.join(base_dir, filename))
    if not full.startswith(os.path.abspath(base_dir) + os.sep):
        raise ValueError("invalid path")
    with open(full, "r") as f:
        return f.read()

